CREATE SEQUENCE user_seq START WITH 100000 INCREMENT BY 1; CREATE SEQUENCE employer_profile_seq START WITH 10000 INCREMENT BY 1; CREATE SEQUENCE vacancy_seq START WITH 100000000 INCREMENT BY 1;
CREATE TABLE roles ( id VARCHAR(255) NOT NULL PRIMARY KEY, name VARCHAR(255) );
CREATE TABLE currency ( id VARCHAR(255) NOT NULL PRIMARY KEY, name VARCHAR(255), abbr VARCHAR(255) );
CREATE TABLE employment ( id VARCHAR(255) NOT NULL PRIMARY KEY, name VARCHAR(255) );
CREATE TABLE experience ( id VARCHAR(255) NOT NULL PRIMARY KEY, name VARCHAR(255) );
CREATE TABLE stack ( id VARCHAR(255) NOT NULL PRIMARY KEY, name VARCHAR(255), search_query VARCHAR(255) );
CREATE TABLE work_format ( id VARCHAR(255) NOT NULL PRIMARY KEY, name VARCHAR(255) );
CREATE TABLE vacancy_direction ( id VARCHAR(64) NOT NULL PRIMARY KEY, name VARCHAR(255) NOT NULL UNIQUE );
CREATE TABLE vacancy_source ( id SMALLINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, code VARCHAR(255) NOT NULL UNIQUE, name VARCHAR(255) NOT NULL, active BOOLEAN NOT NULL DEFAULT TRUE, is_visible BOOLEAN NOT NULL DEFAULT TRUE, base_url VARCHAR(255) NOT NULL, ttl_days INTEGER NOT NULL );
CREATE TABLE key_skill ( id INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, name VARCHAR(255) );
CREATE TABLE learn ( id INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, heading VARCHAR(255), content VARCHAR(255) );
CREATE TABLE question ( id INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, heading VARCHAR(255), content VARCHAR(255) );
CREATE TABLE vacancy_excluded_word ( id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, word VARCHAR(255) NOT NULL UNIQUE, active BOOLEAN NOT NULL DEFAULT TRUE, created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP );
CREATE TABLE users ( id INTEGER NOT NULL DEFAULT NEXTVAL('user_seq') PRIMARY KEY, email VARCHAR(200) UNIQUE, phone_number VARCHAR(20) UNIQUE, password VARCHAR(255), role_id VARCHAR(255), status VARCHAR(255) DEFAULT 'ACTIVE', block_reason VARCHAR(255), blocked_at TIMESTAMP, blocked_until TIMESTAMP, verified BOOLEAN, verification_status SMALLINT, verified_at TIMESTAMP, avatar_url VARCHAR(255), merged_into_id INTEGER, created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP, CONSTRAINT fk_users_role FOREIGN KEY (role_id) REFERENCES roles(id), CONSTRAINT fk_users_merged_into FOREIGN KEY (merged_into_id) REFERENCES users(id) );
CREATE TABLE employer_profile ( id BIGINT NOT NULL DEFAULT NEXTVAL('employer_profile_seq') PRIMARY KEY, user_id INTEGER NOT NULL UNIQUE, company_name VARCHAR(255), city VARCHAR(255), website VARCHAR(255), contact_name VARCHAR(255), phone VARCHAR(255), about TEXT, avatar_url VARCHAR(255), aggregated BOOLEAN DEFAULT FALSE, accredited BOOLEAN, verified BOOLEAN, created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP, CONSTRAINT fk_employer_profile_user FOREIGN KEY (user_id) REFERENCES users(id) );
CREATE TABLE employer_source ( id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, employer_profile_id BIGINT NOT NULL, source_id SMALLINT NOT NULL, external_id VARCHAR(128) NOT NULL, source_name VARCHAR(255), source_url VARCHAR(255), created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP, CONSTRAINT uk_employer_source_external UNIQUE (source_id, external_id), CONSTRAINT fk_employer_source_profile FOREIGN KEY (employer_profile_id) REFERENCES employer_profile(id), CONSTRAINT fk_employer_source_source FOREIGN KEY (source_id) REFERENCES vacancy_source(id) );
CREATE TABLE candidate_profile ( id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, user_id INTEGER NOT NULL UNIQUE, first_name VARCHAR(255), last_name VARCHAR(255), birthday DATE, about TEXT, resume_url VARCHAR(255), portfolio_url VARCHAR(255), preferred_city VARCHAR(255), preferred_work_format VARCHAR(255), preferred_employment VARCHAR(255), expected_salary_from BIGINT, expected_salary_to BIGINT, open_to_work BOOLEAN NOT NULL DEFAULT TRUE, created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP, CONSTRAINT fk_candidate_profile_user FOREIGN KEY (user_id) REFERENCES users(id) );
CREATE TABLE candidate_resume ( id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, candidate_profile_id BIGINT NOT NULL, profession VARCHAR(255) NOT NULL, city VARCHAR(255), expected_salary_from BIGINT, expected_salary_to BIGINT, employment_id VARCHAR(255), work_format_id VARCHAR(255), experience_id VARCHAR(255), about TEXT, archived BOOLEAN DEFAULT FALSE, created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP, CONSTRAINT fk_candidate_resume_profile FOREIGN KEY (candidate_profile_id) REFERENCES candidate_profile(id), CONSTRAINT fk_candidate_resume_employment FOREIGN KEY (employment_id) REFERENCES employment(id), CONSTRAINT fk_candidate_resume_work_format FOREIGN KEY (work_format_id) REFERENCES work_format(id), CONSTRAINT fk_candidate_resume_experience FOREIGN KEY (experience_id) REFERENCES experience(id) );
CREATE TABLE vacancy ( id INTEGER NOT NULL DEFAULT NEXTVAL('vacancy_seq') PRIMARY KEY, external_id VARCHAR(255), public_id VARCHAR(255) UNIQUE, title VARCHAR(255), stack_id VARCHAR(255), direction_id VARCHAR(64), city VARCHAR(255), salary_from BIGINT, salary_to BIGINT, currency_id VARCHAR(255), description TEXT, source_id SMALLINT, is_aggregated BOOLEAN NOT NULL DEFAULT FALSE, status VARCHAR(255) NOT NULL DEFAULT 'APPROVED', employer_id INTEGER, employment_id VARCHAR(255), experience_id VARCHAR(255), work_format_id VARCHAR(255), created_at TIMESTAMP NOT NULL, updated_at TIMESTAMP, expires_at TIMESTAMP NOT NULL, CONSTRAINT fk_vacancy_stack FOREIGN KEY (stack_id) REFERENCES stack(id), CONSTRAINT fk_vacancy_direction FOREIGN KEY (direction_id) REFERENCES vacancy_direction(id), CONSTRAINT fk_vacancy_currency FOREIGN KEY (currency_id) REFERENCES currency(id), CONSTRAINT fk_vacancy_source FOREIGN KEY (source_id) REFERENCES vacancy_source(id), CONSTRAINT fk_vacancy_employer FOREIGN KEY (employer_id) REFERENCES users(id), CONSTRAINT fk_vacancy_employment FOREIGN KEY (employment_id) REFERENCES employment(id), CONSTRAINT fk_vacancy_experience FOREIGN KEY (experience_id) REFERENCES experience(id), CONSTRAINT fk_vacancy_work_format FOREIGN KEY (work_format_id) REFERENCES work_format(id) );
CREATE TABLE candidate_profile_skill ( candidate_profile_id BIGINT NOT NULL, skill_id INTEGER NOT NULL, PRIMARY KEY (candidate_profile_id, skill_id), CONSTRAINT fk_candidate_profile_skill_profile FOREIGN KEY (candidate_profile_id) REFERENCES candidate_profile(id), CONSTRAINT fk_candidate_profile_skill_skill FOREIGN KEY (skill_id) REFERENCES key_skill(id) );
CREATE TABLE candidate_resume_skill ( candidate_resume_id BIGINT NOT NULL, skill_id INTEGER NOT NULL, PRIMARY KEY (candidate_resume_id, skill_id), CONSTRAINT fk_candidate_resume_skill_resume FOREIGN KEY (candidate_resume_id) REFERENCES candidate_resume(id), CONSTRAINT fk_candidate_resume_skill_skill FOREIGN KEY (skill_id) REFERENCES key_skill(id) );
CREATE TABLE vacancy_skill ( vacancy_id INTEGER NOT NULL, skill_id INTEGER NOT NULL, PRIMARY KEY (vacancy_id, skill_id), CONSTRAINT fk_vacancy_skill_vacancy FOREIGN KEY (vacancy_id) REFERENCES vacancy(id), CONSTRAINT fk_vacancy_skill_skill FOREIGN KEY (skill_id) REFERENCES key_skill(id) );
CREATE TABLE vacancy_contacts ( id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, vacancy_id INTEGER NOT NULL, method VARCHAR(255) NOT NULL, value VARCHAR(255), hint VARCHAR(255), CONSTRAINT fk_vacancy_contacts_vacancy FOREIGN KEY (vacancy_id) REFERENCES vacancy(id) );
CREATE TABLE application ( id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, vacancy_id INTEGER NOT NULL, candidate_id INTEGER NOT NULL, resume_id BIGINT, cover_letter TEXT, resume_url VARCHAR(255), status VARCHAR(255) DEFAULT 'PENDING', chosen_contact_method VARCHAR(255), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP, CONSTRAINT uk_application_vacancy_candidate UNIQUE (vacancy_id, candidate_id), CONSTRAINT fk_application_vacancy FOREIGN KEY (vacancy_id) REFERENCES vacancy(id), CONSTRAINT fk_application_candidate FOREIGN KEY (candidate_id) REFERENCES users(id), CONSTRAINT fk_application_resume FOREIGN KEY (resume_id) REFERENCES candidate_resume(id) );
CREATE TABLE favorite_vacancy ( id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, user_id INTEGER, vacancy_id INTEGER, added_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, CONSTRAINT uk_favorite_vacancy_user_vacancy UNIQUE (user_id, vacancy_id), CONSTRAINT fk_favorite_vacancy_user FOREIGN KEY (user_id) REFERENCES users(id), CONSTRAINT fk_favorite_vacancy_vacancy FOREIGN KEY (vacancy_id) REFERENCES vacancy(id) );
CREATE TABLE auth_tokens ( id UUID NOT NULL PRIMARY KEY, value TEXT NOT NULL UNIQUE, user_id INTEGER NOT NULL, type VARCHAR(255) NOT NULL, created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, expires_at TIMESTAMP NOT NULL, used BOOLEAN NOT NULL DEFAULT FALSE, CONSTRAINT fk_auth_tokens_user FOREIGN KEY (user_id) REFERENCES users(id) );
CREATE TABLE refresh_tokens ( id UUID NOT NULL PRIMARY KEY, value TEXT NOT NULL UNIQUE, user_id INTEGER, created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, expires_at TIMESTAMP NOT NULL, revoked BOOLEAN NOT NULL DEFAULT FALSE, CONSTRAINT fk_refresh_tokens_user FOREIGN KEY (user_id) REFERENCES users(id) );
CREATE TABLE blog_article ( id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, title VARCHAR(220) NOT NULL, summary VARCHAR(500), content TEXT NOT NULL, cover_image_url VARCHAR(255), author_id INTEGER NOT NULL, published BOOLEAN NOT NULL DEFAULT TRUE, created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP, CONSTRAINT fk_blog_article_author FOREIGN KEY (author_id) REFERENCES users(id) );

